#include <stdio.h>
#include <stdint.h>
#include <time.h>
#include <stdlib.h>

typedef uint32_t u32;

u32 g_function(u32 a, u32 b, u32 x) {
    u32 temp = (a + b + x) & 0xFF;
    return ((temp << 2) | (temp >> 6)) & 0xFF;
}

u32 f_function(u32 input_val) {
    u32 x[4], y[4];
    for (int i = 0; i < 4; i++) {
        x[i] = input_val & 0xFF;
        input_val >>= 8;
    }
    y[2] = g_function(x[3] ^ x[2], x[1] ^ x[0], 1);
    y[3] = g_function(x[3], y[2], 0);
    y[1] = g_function(x[1] ^ x[0], y[2], 0);
    y[0] = g_function(x[0], y[1], 1);
    u32 output = 0;
    for (int i = 0; i < 4; i++) {
        output |= y[i] << (8 * i);
    }
    return output & 0xFFFFFFFF;
}

// Global to prevent optimization
volatile u32 sink = 0;

int main() {
    u32 ALL_KEYS[65536];
    for (int s = 0; s < 65536; s++) {
        ALL_KEYS[s] = ((u32)s * 1234567) & 0xFFFFFFFF;
    }

    // Warm up
    for (int i = 0; i < 100000; i++) {
        sink += f_function(i);
    }

    clock_t start = clock();
    for (int i = 0; i < 1000000; i++) {
        sink += f_function(i ^ 0x12345678);
    }
    clock_t end = clock();
    double elapsed = (double)(end - start) / CLOCKS_PER_SEC;
    printf("1M f_function calls: %.6f seconds\n", elapsed);
    double rate = 1000000.0 / elapsed;
    printf("Rate: %.0f calls/sec\n", rate);

    // Estimate time for various workloads
    double est_full = (65536.0 * 65536.0 * 2.0) / rate;
    printf("Estimated time for full 4.3B f-calls: %.1f seconds\n", est_full);

    // The actual attack: for each of 65536 k5, we check 65536 k4 values
    // For wrong k5, each k4 check does 2 f-calls (check pair 0), fails, next
    // So 65536 * 65536 * 2 = 8.6B f-calls for wrong k5
    // Plus for correct k5, we do an extra 2 f-calls (check pair 1)
    // Actual: on average we find correct k5 after checking half of k5 candidates
    // For each wrong k5: 65536*2 = 131072 f-calls
    // For correct k5: 32768*2 + 2 = 65538 f-calls
    // Total: 32768 * 131072 + 65538 ≈ 4.3B f-calls

    // But we can quick-reject: for wrong k5, check only 200 k4 values
    // Probability a random k4 matches T0: 1/2^32 ≈ 2.3e-10
    // So after checking 200 k4, almost all wrong k5 are rejected
    // This gives 65536 * 200 * 2 = 26.2M f-calls for wrong k5
    // Plus 65536 * 65536 * 2 = 8.6B for the correct k5 (worst-case)
    // Expected: ~4.3B f-calls for correct k5
    // Total: ~4.3B + 26.2M ≈ 4.3B (still dominated by correct k5)

    printf("\nWith quick rejection (200 k4 checks per wrong k5):\n");
    double est_quick = (65536.0 * 200.0 * 2.0 + 32768.0 * 65536.0 * 2.0) / rate;
    printf("Estimated time: %.1f seconds\n", est_quick);

    return 0;
}
